    @Nested
    @DisplayName("AC3: 系统预置栏目保护")
    class AC3_SystemColumnProtection {

        @Test
        @DisplayName("4.1-UNIT-007: delete 系统预置栏目（is_system=1）抛 BusinessException(422)")
        void delete_systemColumn_throwsBusinessException() {
            when(columnMapper.selectById(1L)).thenReturn(systemColumn);

            assertThatThrownBy(() -> columnService.delete(1L))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("系统预置栏目不可删除");

            verify(columnMapper, never()).deleteById(any(Long.class));
        }

        @Test
        @DisplayName("4.1-UNIT-008: update 系统预置栏目修改 code 字段抛 BusinessException(422)")
        void update_systemColumn_changeCode_throwsBusinessException() {
            when(columnMapper.selectById(1L)).thenReturn(systemColumn);

            UpdateColumnRequest request = new UpdateColumnRequest();
            request.setCode("new-code");

            assertThatThrownBy(() -> columnService.update(1L, request))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("系统预置栏目代码不可修改");

            verify(columnMapper, never()).updateById(any(Column.class));
        }

        @Test
        @DisplayName("4.1-UNIT-009: update 系统预置栏目可修改 name/is_visible/sort_order/icon/route_path")
        void update_systemColumn_allowedFields_success() {
            when(columnMapper.selectById(1L)).thenReturn(systemColumn);
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class))).thenReturn(0L);
            when(columnMapper.updateById(any(Column.class))).thenReturn(1);

            UpdateColumnRequest request = new UpdateColumnRequest();
            request.setName("新首页");
            request.setIsVisible(false);
            request.setSortOrder(99);
            request.setIcon("new-icon");
            request.setRoutePath("/new-home");

            columnService.update(1L, request);

            verify(columnMapper).updateById(argThat(col ->
                    "新首页".equals(col.getName())
                            && Boolean.FALSE.equals(col.getIsVisible())
                            && col.getSortOrder().equals(99)
                            && "new-icon".equals(col.getIcon())
                            && "/new-home".equals(col.getRoutePath())
            ));
        }
    }

