    @Nested
    @DisplayName("AC4: 栏目删除保护（关联内容）")
    class AC4_RelatedContentProtection {

        @Test
        @DisplayName("4.1-UNIT-010: delete 有关联二级栏目的栏目抛 BusinessException(422)")
        void delete_columnWithChildren_throwsBusinessException() {
            Column colWithChildren = new Column();
            colWithChildren.setId(20L);
            colWithChildren.setName("有子栏目");
            colWithChildren.setCode("with-children");
            colWithChildren.setIsSystem(false);

            when(columnMapper.selectById(20L)).thenReturn(colWithChildren);
            when(subColumnService.existsByColumnId(20L)).thenReturn(true);

            assertThatThrownBy(() -> columnService.delete(20L))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("该栏目下有关联内容");

            verify(columnMapper, never()).deleteById(any(Long.class));
        }

        @Test
        @DisplayName("4.1-UNIT-011: hasChildren 委托 SubColumnService.existsByColumnId")
        void hasChildren_delegatesToSubColumnService() {
            when(subColumnService.existsByColumnId(1L)).thenReturn(false);
            when(subColumnService.existsByColumnId(3L)).thenReturn(true);

            assertThat(columnService.hasChildren(1L)).isFalse();
            assertThat(columnService.hasChildren(3L)).isTrue();

            verify(subColumnService).existsByColumnId(1L);
            verify(subColumnService).existsByColumnId(3L);
        }

        @Test
        @DisplayName("4.1-UNIT-012: delete 无关联且非系统预置的栏目成功（软删除）")
        void delete_customColumnNoChildren_softDeletes() {
            when(columnMapper.selectById(10L)).thenReturn(customColumn);
            when(columnMapper.deleteById(10L)).thenReturn(1);

            columnService.delete(10L);

            // deleteById triggers @TableLogic soft delete (sets deleted_at = NOW())
            verify(columnMapper).deleteById(10L);
        }
    }

