    @Nested
    @DisplayName("AC5: 编辑生效与公开 API")
    class AC5_CrudAndPublicApi {

        @Test
        @DisplayName("4.1-UNIT-013: create 栏目成功，字段正确持久化")
        void create_validRequest_persistsCorrectly() {
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class))).thenReturn(0L);
            when(columnMapper.insert(any(Column.class))).thenAnswer(invocation -> {
                Column col = invocation.getArgument(0);
                col.setId(100L);
                return 1;
            });

            CreateColumnRequest request = new CreateColumnRequest();
            request.setName("测试栏目");
            request.setCode("test-col");
            request.setSortOrder(10);
            request.setRoutePath("/test");

            Long id = columnService.create(request);

            assertThat(id).isEqualTo(100L);
            verify(columnMapper).insert(argThat(col ->
                    "测试栏目".equals(col.getName())
                            && "test-col".equals(col.getCode())
                            && col.getSortOrder().equals(10)
                            && Boolean.FALSE.equals(col.getIsSystem())
                            && Boolean.TRUE.equals(col.getIsVisible())
            ));
        }

        @Test
        @DisplayName("4.1-UNIT-014: create 栏目名称重复抛 BusinessException(422)")
        void create_duplicateName_throwsBusinessException() {
            // First selectCount for name check returns 1 (duplicate)
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class))).thenReturn(1L);

            CreateColumnRequest request = new CreateColumnRequest();
            request.setName("测试");
            request.setCode("test");

            assertThatThrownBy(() -> columnService.create(request))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("栏目名称已存在");

            verify(columnMapper, never()).insert(any());
        }

        @Test
        @DisplayName("4.1-UNIT-015: create 栏目代码重复抛 BusinessException(422)")
        void create_duplicateCode_throwsBusinessException() {
            // First selectCount for name → 0, second for code → 1
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class)))
                    .thenReturn(0L)
                    .thenReturn(1L);

            CreateColumnRequest request = new CreateColumnRequest();
            request.setName("新栏目");
            request.setCode("existing-code");

            assertThatThrownBy(() -> columnService.create(request))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("栏目代码已存在");

            verify(columnMapper, never()).insert(any());
        }

        @Test
        @DisplayName("4.1-UNIT-016: update 栏目成功，字段正确更新")
        void update_validRequest_updatesCorrectly() {
            when(columnMapper.selectById(10L)).thenReturn(customColumn);
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class))).thenReturn(0L);
            when(columnMapper.updateById(any(Column.class))).thenReturn(1);

            UpdateColumnRequest request = new UpdateColumnRequest();
            request.setName("新名称");

            columnService.update(10L, request);

            verify(columnMapper).updateById(argThat(col ->
                    "新名称".equals(col.getName())
                            && "custom".equals(col.getCode()) // unchanged
            ));
        }

        @Test
        @DisplayName("4.1-UNIT-017: update 栏目名称改为已存在名称抛异常")
        void update_duplicateName_throwsBusinessException() {
            when(columnMapper.selectById(10L)).thenReturn(customColumn);
            when(columnMapper.selectCount(any(LambdaQueryWrapper.class))).thenReturn(1L);

            UpdateColumnRequest request = new UpdateColumnRequest();
            request.setName("已存在名称");

            assertThatThrownBy(() -> columnService.update(10L, request))
                    .isInstanceOf(BusinessException.class)
                    .hasMessageContaining("栏目名称已存在");

            verify(columnMapper, never()).updateById(any());
        }

        @Test
        @DisplayName("4.1-UNIT-018: listVisible 仅返回 is_visible=1 且未软删除的栏目，按 sort_order 升序")
        void listVisible_returnsOnlyVisibleUndeletedColumnsSorted() {
            Column visible = new Column();
            visible.setId(1L);
            visible.setName("可见");
            visible.setCode("visible");
            visible.setIsSystem(false);
            visible.setIsVisible(true);
            visible.setSortOrder(1);
            visible.setCreatedAt(LocalDateTime.now());
            visible.setUpdatedAt(LocalDateTime.now());

            // @TableLogic automatically filters deleted_at IS NULL
            // The wrapper also adds isVisible = true
            when(columnMapper.selectList(any(LambdaQueryWrapper.class)))
                    .thenReturn(List.of(visible));

            List<ColumnResponse> result = columnService.listVisible();

            assertThat(result).hasSize(1);
            assertThat(result.get(0).getName()).isEqualTo("可见");
            assertThat(result.get(0).getIsVisible()).isTrue();
        }

        @Test
        @DisplayName("4.1-UNIT-019: delete 成功执行软删除（设置 deleted_at，非物理删除）")
        void delete_softDeleteSetsDeletedAt() {
            when(columnMapper.selectById(10L)).thenReturn(customColumn);
            when(columnMapper.deleteById(10L)).thenReturn(1);

            columnService.delete(10L);

            // BaseEntity @TableLogic converts deleteById to UPDATE SET deleted_at = NOW()
            verify(columnMapper).deleteById(10L);
            // Verify no physical delete call (no SQL DELETE)
        }
    }

    // ============================================================
    // Blind Spot Scenarios [BLIND-SPOT]
